-- Mark iconic Changi amenities as flagship
UPDATE amenities
SET flagship = true
WHERE name IN (
  'Rain Vortex',
  'Canopy Park',
  'Butterfly Garden',
  'Jewel Waterfall Viewpoint',
  'Changi Experience Studio',
  'Shiseido Forest Valley'
)
AND airport_code = 'SIN';

-- Set brand_family for duplicate attractions across terminals
UPDATE amenities SET brand_family = 'rain_vortex' WHERE name = 'Rain Vortex' AND airport_code = 'SIN';
UPDATE amenities SET brand_family = 'canopy_park' WHERE name = 'Canopy Park' AND airport_code = 'SIN';
